import re
import subprocess
from pathlib import Path


def scan_repos_for_model(
    model_id: str,
    repos_root: Path,
    extensions: tuple = (".py", ".ts", ".js", ".env", ".yaml", ".json"),
) -> dict[str, list[str]]:
    """
    Walk all repos under repos_root, return {repo_path: [matching_files]}.
    Searches for the exact model_id string.
    """
    pattern = re.compile(re.escape(model_id))
    hits: dict[str, list[str]] = {}

    for repo_dir in sorted(repos_root.iterdir()):
        if not repo_dir.is_dir():
            continue
        matches = []
        for ext in extensions:
            for file in repo_dir.rglob(f"*{ext}"):
                try:
                    text = file.read_text(errors="ignore")
                    if pattern.search(text):
                        matches.append(str(file.relative_to(repo_dir)))
                except OSError:
                    continue
        if matches:
            hits[repo_dir.name] = matches

    return hits


if __name__ == "__main__":
    results = scan_repos_for_model(
        model_id="gpt-3.5-turbo-0301",
        repos_root=Path("/workspace/repos"),
    )
    for repo, files in results.items():
        print(f"{repo}: {len(files)} file(s)")
        for f in files:
            print(f"  {f}")
